export default function deepClone(value) {
  const seen = new Map();

  function cloneRec(v) {
    if (v === null || typeof v !== 'object') return v;

    if (seen.has(v)) return seen.get(v);

    const out = Array.isArray(v) ? [] : {};
    seen.set(v, out);

    for (const key in v) {
      out[key] = cloneRec(v[key]);
    }

    return out;
  }

  return cloneRec(value);
}
